const data = $input.first().json.body || $input.first().json;
const token = data.token;
if (!token) return [{ json: { success: false, error: 'Token required' } }];
try {
  const parts = token.split('.');
  const payload = JSON.parse(Buffer.from(parts[1], 'base64').toString());
  if (payload.exp && payload.exp * 1000 < Date.now()) return [{ json: { success: false, error: 'Token expired' } }];
  const userId = payload.sub || payload.user_id || payload.id;
  if (!userId) return [{ json: { success: false, error: 'Invalid token' } }];
  return [{ json: { ...data, user_id: userId, _auth: true } }];
} catch(e) { return [{ json: { success: false, error: 'Invalid token' } }]; }

const vendorIds = $input.first().json;
const ids = Array.isArray(vendorIds) ? vendorIds.map(v => v.id) : [];
if (ids.length === 0) return [{ json: { success: true, logs: [] } }];
const SUPABASE_URL = 'https://prometeix-servidor-supabase.reyl9a.easypanel.host/rest/v1';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyAgCiAgICAicm9sZSI6ICJzZXJ2aWNlX3JvbGUiLAogICAgImlzcyI6ICJzdXBhYmFzZS1kZW1vIiwKICAgICJpYXQiOiAxNjQxNzY5MjAwLAogICAgImV4cCI6IDE3OTk1MzU2MDAKfQ.DaYlNEoUrrEn2Ig7tqibS-PHK5vgusbcbo7X36XVt4Q';
try {
  const idsParam = ids.map(i => encodeURIComponent(i)).join(',');
  const resp = await fetch(`${SUPABASE_URL}/sync_logs?vendor_id=in.(${idsParam})&order=started_at.desc&limit=20`, {
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
  });
  const logs = await resp.json();
  // Get vendor names for display
  const vendorResp = await fetch(`${SUPABASE_URL}/vendors?id=in.(${idsParam})&select=id,name`, {
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
  });
  const vendors = await vendorResp.json();
  const vendorMap = {};
  for (const v of vendors) vendorMap[v.id] = v.name;
  const enriched = (Array.isArray(logs) ? logs : []).map(l => ({ ...l, vendor_name: vendorMap[l.vendor_id] || 'Unknown' }));
  return [{ json: { success: true, logs: enriched } }];
} catch(e) {
  return [{ json: { success: true, logs: [], error: e.message } }];
}
